  1→import type { DimensionAnalysisInput } from "@rudel/api-routes";
  2→import { useQuery } from "@tanstack/react-query";
  3→import { Activity, Clock, Timer } from "lucide-react";
  4→import { useEffect, useMemo, useState } from "react";
  5→import { Link } from "react-router-dom";
  6→import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
  7→import { DatePicker } from "@/components/analytics/DatePicker";
  8→import { MultiSelect } from "@/components/analytics/MultiSelect";
  9→import { PageHeader } from "@/components/analytics/PageHeader";
 10→import { StatCard } from "@/components/analytics/StatCard";
 11→import { DimensionAnalysisChart } from "@/components/charts/DimensionAnalysisChart";
 12→import {
 13→	Select,
 14→	SelectContent,
 15→	SelectItem,
 16→	SelectTrigger,
 17→	SelectValue,
 18→} from "@/components/ui/select";
 19→import { Spinner } from "@/components/ui/spinner";
 20→import { Switch } from "@/components/ui/switch";
 21→import {
 22→	Table,
 23→	TableBody,
 24→	TableCell,
 25→	TableHead,
 26→	TableHeader,
 27→	TableRow,
 28→} from "@/components/ui/table";
 29→import { useDateRange } from "@/contexts/DateRangeContext";
 30→import { calculateCost, formatUsername } from "@/lib/format";
 31→import { orpc } from "@/lib/orpc";
 32→
 33→export function SessionsListPage() {
 34→	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
 35→		useDateRange();
 36→	const days = calculateDays();
 37→
 38→	const [selectedRepositories, setSelectedRepositories] = useState<string[]>(
 39→		[],
 40→	);
 41→	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
 42→
 43→	const [selectedDimension, setSelectedDimension] =
 44→		useState<DimensionAnalysisInput["dimension"]>("repository");
 45→	const [selectedMetric, setSelectedMetric] =
 46→		useState<DimensionAnalysisInput["metric"]>("session_count");
 47→	const [selectedSplitBy, setSelectedSplitBy] = useState<
 48→		DimensionAnalysisInput["dimension"] | ""
 49→	>("");
 50→	const [showPercentage, setShowPercentage] = useState(false);
 51→
 52→	const [debouncedDimension, setDebouncedDimension] =
 53→		useState<DimensionAnalysisInput["dimension"]>("repository");
 54→	const [debouncedMetric, setDebouncedMetric] =
 55→		useState<DimensionAnalysisInput["metric"]>("session_count");
 56→	const [debouncedSplitBy, setDebouncedSplitBy] = useState<
 57→		DimensionAnalysisInput["dimension"] | ""
 58→	>("");
 59→
 60→	useEffect(() => {
 61→		const timer = setTimeout(() => {
 62→			setDebouncedDimension(selectedDimension);
 63→			setDebouncedMetric(selectedMetric);
 64→			setDebouncedSplitBy(selectedSplitBy);
 65→		}, 300);
 66→		return () => clearTimeout(timer);
 67→	}, [selectedDimension, selectedMetric, selectedSplitBy]);
 68→
 69→	const { data: summary } = useQuery(
 70→		orpc.analytics.sessions.summary.queryOptions({ input: { days } }),
 71→	);
 72→
 73→	const { data: comparison } = useQuery(
 74→		orpc.analytics.sessions.summaryComparison.queryOptions({
 75→			input: { days },
 76→		}),
 77→	);
 78→
 79→	const { data: sessions, isLoading } = useQuery(
 80→		orpc.analytics.sessions.list.queryOptions({
 81→			input: { days, limit: 100, sortBy: "session_date", sortOrder: "desc" },
 82→		}),
 83→	);
 84→
 85→	const { data: userMappings } = useQuery(
 86→		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
 87→	);
 88→
 89→	const { data: dimensionData, isLoading: dimensionLoading } = useQuery(
 90→		orpc.analytics.sessions.dimensionAnalysis.queryOptions({
 91→			input: {
 92→				days,
 93→				dimension: debouncedDimension,
 94→				metric: debouncedMetric,
 95→				splitBy: debouncedSplitBy || undefined,
 96→				limit: 10,
 97→			},
 98→		}),
 99→	);
100→
101→	const userMap = useMemo(() => {
102→		const map = new Map<string, string>();
103→		if (userMappings) {
104→			for (const m of userMappings) {
105→				map.set(m.user_id, m.username);
106→			}
107→		}
108→		return map;
109→	}, [userMappings]);
110→
111→	const userMapRecord = useMemo(() => Object.fromEntries(userMap), [userMap]);
112→
113→	const filteredSessions = useMemo(() => {
114→		if (!sessions) return [];
115→		return sessions.filter((session) => {
116→			const repoMatch =
117→				selectedRepositories.length === 0 ||
118→				(session.repository &&
119→					selectedRepositories.includes(session.repository));
120→			const userMatch =
121→				selectedUsers.length === 0 || selectedUsers.includes(session.user_id);
122→			return repoMatch && userMatch;
123→		});
124→	}, [sessions, selectedRepositories, selectedUsers]);
125→
126→	const repositories = useMemo(() => {
127→		if (!sessions) return [];
128→		return Array.from(
129→			new Set(sessions.map((s) => s.repository).filter(Boolean)),
130→		).sort() as string[];
131→	}, [sessions]);
132→
133→	const users = useMemo(() => {
