 14→export function LearningsPage() {
 15→	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
 16→		useDateRange();
 17→	const days = calculateDays();
 18→
 19→	const [splitBy, setSplitBy] = useState<"user_id" | "repository">("user_id");
 20→	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
 21→	const [selectedProjects, setSelectedProjects] = useState<string[]>([]);
 22→
 23→	const { data: learnings, isLoading } = useQuery(
 24→		orpc.analytics.learnings.list.queryOptions({
 25→			input: { days, limit: 100, offset: 0 },
 26→		}),
 27→	);
 28→
 29→	const { data: stats } = useQuery(
 30→		orpc.analytics.learnings.stats.queryOptions({ input: { days } }),
 31→	);
 32→
 33→	const { data: trendData } = useQuery(
 34→		orpc.analytics.learnings.trend.queryOptions({
 35→			input: { days, splitBy },
 36→		}),
 37→	);
 38→
 39→	const { data: availableUsers } = useQuery(
 40→		orpc.analytics.learnings.users.queryOptions({}),
 41→	);
 42→
 43→	const { data: availableProjects } = useQuery(
 44→		orpc.analytics.learnings.projects.queryOptions({}),
 45→	);
 46→
 47→	const { data: userMappings } = useQuery(
 48→		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
 49→	);
 50→
 51→	const userMap = useMemo(() => {
 52→		const map = new Map<string, string>();
 53→		if (userMappings) {
 54→			for (const m of userMappings) {
 55→				map.set(m.user_id, m.username);
 56→			}
 57→		}
 58→		return map;
 59→	}, [userMappings]);
 60→
 61→	const userDisplayOptions = useMemo(() => {
 62→		if (!availableUsers) return [];
 63→		return availableUsers.map(
 64→			(userId) => userMap.get(userId) || `${userId.substring(0, 8)}...`,
 65→		);
 66→	}, [availableUsers, userMap]);
 67→
 68→	const projectDisplayOptions = useMemo(() => {
 69→		if (!availableProjects) return [];
 70→		return availableProjects.map((path) => {
 71→			const name = path.split("/").pop() || path;
