 79→			if (
 80→				selectedUsers.length > 0 &&
 81→				!selectedUsers.includes(learning.user_id)
 82→			) {
 83→				return false;
 84→			}
 85→			if (
 86→				selectedProjects.length > 0 &&
 87→				!selectedProjects.includes(learning.project_path)
 88→			) {
