160→						</p>
161→					</div>
162→				</AnalyticsCard>
163→			)}
164→
165→			{hasData && (
166→				<>
167→					{/* Stats Overview */}
168→					{stats && (
169→						<div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
