  3→import { Navigate, Route, Routes } from "react-router-dom";
  4→import { LoginForm } from "./components/auth/login-form";
  5→import { SignupForm } from "./components/auth/signup-form";
  6→import { DashboardLayout } from "./layouts/DashboardLayout";
  7→import { authClient } from "./lib/auth-client";
  8→import { AcceptInvitationPage } from "./pages/AcceptInvitationPage";
  9→import { CreateOrgPage } from "./pages/dashboard/CreateOrgPage";
 10→import { DeveloperDetailPage } from "./pages/dashboard/DeveloperDetailPage";
